    func parsePromo(from url: URL) -> PromoOffer? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }
        guard components.host == "myapp.com" || components.host == "www.myapp.com" else { return nil }
        guard components.path == "/promo" else { return nil }

        let items = components.queryItems ?? []
        guard let code = items.first(where: { $0.name == "code" })?.value,
              let discountString = items.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString),
              (0...100).contains(discount) else {
            return nil
        }

        return PromoOffer(code: code, discountPercentage: discount)
    }

    func applyPromo(_ promo: PromoOffer, to user: UserAccount) {
        user.appliedPromoCode = promo.code
        user.discountPercentage = promo.discountPercentage
        user.save()
    }
}

final class UserAccount {
    var userId: String
    var appliedPromoCode: String?
